INSERT INTO `test_cases` VALUES (2, 'tc_1773799891395', 'TC-002', '1773551503497', 0, 'เพิ่มข้อมูลกลุ่มบริหารลูกหนี้', 'ชื่อกลุ่ม\nกำหนดผังบัญชีเดบิต\nกำหนดผังบัญชีเครดิต\nตั้งค่าติดตามลูกหนี้รายตัว\nกำหนดประเภทผู้ป่วย\nสามารถตั้งค่าตั้งหนี้กับคนไข้ได้\nกำหนดกองทุนหลัก', '[{\"action\":\"1.คลิกที่เมนูกลุ่มบริหารงานลูกหนี้\",\"expected\":\"สามารถเพิ่มข้อมูลบริหารงานลูกหนี้ได้\"},{\"action\":\"2.กดปุ่มเพิ่ม\",\"expected\":\"สามารถเปิดหน้าจอบันทึกข้อมูลได้\"},{\"action\":\"3.กรอกข้อมูลรายละเอียดด้านใน\\n? ชื่อกลุ่ม\\n? กำหนดผังบัญชีเดบิต\\n? กำหนดผังบัญชีเครดิต\\n? ตั้งค่าติดตามลูกหนี้รายตัว\\n? กำหนดประเภทผู้ป่วย\\n? สามารถตั้งค่าตั้งหนี้กับคนไข้ได้\\n? กำหนดกองทุนหลัก\",\"expected\":\"สามารถกรอกข้อมูลรายละเอียดด้านในได้ และเมื่อบันทึกข้อมูลไม่เพี้ยน\"}]', 'สามารถเพิ่มข้อมูลได้ โดยสามารถกำหนดรายละเอียดภายในได้ ', 'pass', 'พิจิตรา ไตรสุธา', '2026-03-18', NULL, '2026-03-18 09:11:27');
INSERT INTO `test_cases` VALUES (3, 'tc_1773800473592', 'TC-003', '1773547775589', 0, 'เพิ่มชื่อแผนกฝั่งบัญชี', 'สามารถเพิ่มชื่อแผนกได้', '[{\"action\":\"คลิกที่ระบบพื้นฐานเจ้าหนี้\",\"expected\":\"แสดงรายละเอียดเมนูย่อยในระบบพื้นฐานเจ้าหนี้\"},{\"action\":\"คลิกเมนู department\",\"expected\":\"แสดงหน้าจอแท็บการ map แผนก และ แท็บแผนกบัญชี\"},{\"action\":\"คลิกแท็บแผนกบัญชี\",\"expected\":\"แสดงข้อมูลที่มีอยู่ของแผนกบัญชีทั้งหมด\"},{\"action\":\"คลิก เพิ่ม\",\"expected\":\"แสดง pop up ให้เพิ่มชื่อแผนก\"},{\"action\":\"พิมพ์ชื่อแผนก\",\"expected\":\"สามารถพิมพ์ชื่อได้ทั้ง ไทยและอังกฤษ\"},{\"action\":\"คลิกปุ่ม บันทึก\",\"expected\":\"ระบบบันทึกข้อมูลแผนกที่เพิ่ม และสามารถนำไป map ได้\"}]', 'สามารถเพิ่มและนำไป map ได้', 'pass', 'น้องเจี๊ยบ', '2026-03-18', NULL, '2026-03-18 09:20:52');
INSERT INTO `test_cases` VALUES (4, 'tc_1773800798568', 'TC-003', '1773551601244', 0, 'ทดสอบเชื่อมต่อผังบัญชี', NULL, '[{\"action\":\"ประเภท\",\"expected\":\"ระบบแสดงประเภท\"},{\"action\":\"ชื่อ\",\"expected\":\"ระบบแสดงชื่อรายการ\"},{\"action\":\"Debit\",\"expected\":\"ระบบแสดงยอด Debit\"},{\"action\":\"Credit\",\"expected\":\"ระบบแสดงยอด Credit\"}]', 'ไม่สามารถเพิ่มข้อมูลได้', 'fail', 'V', '2026-03-18', NULL, '2026-03-18 09:26:16');
INSERT INTO `test_cases` VALUES (5, 'tc_1773801130689', 'TC-004', '1773547775589', 1, 'สามารถนำเข้าไฟล์ที่เป็นข้อมูลแผนกจาก inv. มาเข้าแผนกบัญชีได้', 'เมื่อนำไฟล์เข้าแผนกบัญชีจะต้องมีแผนกจากไฟล์ที่นำเข้าโดยตรวจสอบชื่อแผนกที่ซ้ำไม่ต้องเพิ่ม', '[{\"action\":\"คลิก เมนู Department\",\"expected\":\"แสดงหน้าจอแท็บ map แผนก และแท็บแผนกบัญชี\"},{\"action\":\"คลิก แท็บแผนกบัญชี\",\"expected\":\"แสดงข้อมูลแผนกบัญชีทั้งหมด\"},{\"action\":\"คลิกปุ่ม import \",\"expected\":\"เด้งหน้าจอให้เลือกไฟล์นำเข้า\"},{\"action\":\"เลือกไฟล์\",\"expected\":\"ระบบตรวจสอบข้อมูลในไฟล์และเพิ่มข้อมูลแผนกโดยข้ามชื่อที่ซ้ำ\"}]', 'สามารถนำเข้าไฟล์ได้และไม่เพิ่มชื่อแผนกที่ซ้ำกัน', 'pass', 'น้องเจี๊ยบ', '2026-03-18', NULL, '2026-03-18 09:31:50');
INSERT INTO `test_cases` VALUES (6, 'tc_1773801177274', 'TC-004', '1773551503497', 1, 'กำหนดสิทธิการรักษา', 'สามารถผูกสิทธิการรักษากับข้อมูลกลุ่มบริหารงานลูกหนี้ได้', '[{\"action\":\"1. ค้นหาสิทธิการรักษา\",\"expected\":\"ค้นหาสิทธิการรักษาได้\"},{\"action\":\"2. กดบันทึก\",\"expected\":\"สามารถกดบันทึกได้ โดยไม่ขึ้น error\"}]', 'สามารถผูกสิทธิการรักษากับกลุ่มบริหารงานลูกหนี้ได้ ', 'pass', 'พิจิตรา ไตรสุธา', '2026-03-18', NULL, '2026-03-18 09:32:53');
INSERT INTO `test_cases` VALUES (7, 'tc_1773801705560', 'TC-005', '1773665576288', 0, 'ทดสอบเบิกเล่มใบเสร็จ', NULL, '[{\"action\":\"แสดงข้อมูลประวัติการเบิกเล่มใบเสร็จ\",\"expected\":\"สามารถแสดงข้อมูลประวัติการเบิกเล่มใบเสร็จ\"},{\"action\":\"สามารถทำการเพิ่มการเบิกเล่มใบเสร็จที่แยกตามประเภทงบประมาณเพื่อให้รันเล่มที่/เลขที่ได้\",\"expected\":\"สามารถทำการเพิ่มการเบิกเล่มใบเสร็จที่แยกตามประเภทงบประมาณเพื่อให้รันเล่มที่/เลขที่ได้\"},{\"action\":\"เล่มใบเสร็จที่ทำการบันทึกเบิกในระบบสามารถไปใช้ออกใบเสร็จได้ทั้งบันทึกรับเงินโอนจากกองทุนและระบบรายได้\",\"expected\":\"เล่มใบเสร็จที่ทำการบันทึกเบิกในระบบสามารถไปใช้ออกใบเสร็จได้ทั้งบันทึกรับเงินโอนจากกองทุนและระบบรายได้\"}]', 'ไม่สามารถทำการทดสอบได้เนื่องจากกดไม่มีปุ่มให้เพิ่มข้อมูล', 'fail', 'V', '2026-03-18', NULL, '2026-03-18 09:41:23');
INSERT INTO `test_cases` VALUES (8, 'tc_1773801816550', 'TC-005', '1773551535989', 0, 'เพิ่มกองทุนเพื่อผูกผังบัญชี', 'สามารถเพิ่มกองทุนเพื่อผูกผังบัญชีได้', '[{\"action\":\"1. คลิกที่ ประเภทกองทุน สปสช.\",\"expected\":\"สามารถบันทึกข้อมูลได้\"},{\"action\":\"2. กดเพิ่ม\",\"expected\":\"สามารถเปิดเพื่อเพิ่มประเภทกองทุนได้\"},{\"action\":\"3. เพิ่มข้อมูลรายละเอียด\\n? ชื่อกองทุน\\n? บัญชี Debit\\n? บัญชี Credit\\n? กลุ่มสิทธิ\\n? การประมวลผล\\n? หมายเหตุ\",\"expected\":\"สามารถเพิ่มข้อมูลตามรายละเอียดได้\"},{\"action\":\"4. กดบันทึก\",\"expected\":\"สามารถบันทึกข้อมูลได้\"}]', 'สามารถบันทึกข้อมูลประเภทกองทุนได้ ', 'pass', 'พิจิตรา ไตรสุธา', '2026-03-18', NULL, '2026-03-18 09:43:32');
INSERT INTO `test_cases` VALUES (9, 'tc_1773802052962', 'TC-005', '1773547775589', 2, 'map ข้อมูลแผนกบัญชีและ inv.ได้', 'สามารถนำข้อมูลแผนกบัญชีมา map กับข้อมูลแผนก inv. ได้', '[{\"action\":\"คลิกเมนู department \",\"expected\":\"แสดงแท็บ map แผนก และแท็บแผนกบัญชี\"},{\"action\":\"เลือก map แผนก\",\"expected\":\"สามารถคลิก drop down เลือกแผนกบัญชีหรือคีย์ค้นหาแผนกทีต้องการ map ได้\"}]', 'สามาถเลือกแผนกบัญชีมา map กับแผนก inv. ได้', 'pass', 'น้องเจี๊ยบ', '2026-03-18', NULL, '2026-03-18 09:47:12');
INSERT INTO `test_cases` VALUES (10, 'tc_1773803084865', 'TC-006', '1773665080710', 0, 'กรองข้อมูลใบแจ้งหนี้จาก HOSxP ได้ ตามช่วงระยะเวลา', 'สามารถกรองข้อมูลได้ถูกต้อง', '[{\"action\":\"1. คลิกนำเข้าใบแจ้งหนี้\",\"expected\":\"สามารถคลิกเพื่อเปิดเมนูได้\"},{\"action\":\"2. เลือกประเภทกองทุนหรือกลุ่มลูกหนี้\",\"expected\":\"สามารถเลือกกรองได้\"},{\"action\":\"3. กรองข้อมูลตามช่วงเวลา\",\"expected\":\"สามารถเลือกช่วงเวลาที่ต้องการได้\"},{\"action\":\"4. กดปุ่ม แสดงข้อมูล\",\"expected\":\"แสดงใบแจ้งหนี้จาก HOSxP ตามกลุ่มหรือกองทุน และช่วงระยะเวลา ได้ถูกต้อง\"}]', 'สามารถกรองข้อมูลได้ถูกต้องตามระยะเวลา และกองทุน', 'pass', 'พิจิตรา ไตรสุธา', '2026-03-18', NULL, '2026-03-18 10:04:41');
INSERT INTO `test_cases` VALUES (11, 'tc_1773803379392', 'TC-006', '1773547829397', 0, 'สามารถนำข้อมูลประเภทรายการสินค้าจากระบบบัญชีมา map กับ ประเภทรายการสินค้าจากระบบinv.', NULL, '[{\"action\":\"คลิกเมนูข้อมูลประเภทสินค้า\",\"expected\":\"แสดงหน้าจอการ map ข้อมูลประเภทสินค้าระหว่างข้อมูลจากบัญชีและข้อมูลจาก รnv.\"}]', 'หน้าจอแสดงข้อมูลประเภท inv. มีช่องให้เลือก map ประเภทสินค้าจากบัญชี ', 'pending', NULL, NULL, NULL, '2026-03-18 10:09:18');
INSERT INTO `test_cases` VALUES (12, 'tc_1773803659378', 'TC-007', '1773665080710', 1, 'สามารถกรองข้อมูลตามกลุ่มลูกหนี้', 'เมื่อกรองข้อมูลแล้วแสดงข้อมูลตามกลุ่มลูกหนี้ได้ถูกต้อง', '[{\"action\":\"1. คลิกที่กลุ่มลูกหนี้\",\"expected\":\"สามารถคลิกเพื่อกรองข้อมูลได้\"},{\"action\":\"2. คลิกเลือกกลุ่มลูกหนี้\",\"expected\":\"สามารถเลือกกลุ่มลูกหนี้ที่ต้องการกรองได้\"},{\"action\":\"3. คลิกแสดงข้อมูล\",\"expected\":\"แสดงข้อมูลได้ถูกต้องตามสิทธิที่มีการกำหนดไว้\"}]', 'สามารถกรองข้อมูลได้ถูกต้องตามตามกลุ่มลูกหนี้ที่เลือก และสิทธิที่แสดงถูกต้องตามที่กำหนดไว้', 'pass', 'พิจิตรา ไตรสุธา', '2026-03-18', NULL, '2026-03-18 10:14:15');
INSERT INTO `test_cases` VALUES (13, 'tc_1773803886551', 'TC-008', '1773665080710', 2, 'สามารถกรองข้อมูลตามกองทุนได้', 'สามารถกรองข้อมูลตามกองทุนได้ และแสดงข้อมูลถูกต้องตามสิทธิ', '[{\"action\":\"1. คลิกที่กองทุน\",\"expected\":\"สามารถคลิกที่กองทุนเพื่อกรองข้อมูลได้\"},{\"action\":\"2. เลือกกองทุน\",\"expected\":\"สามารถกรองข้อมูลกองทุนได้ตามที่เลือก\"},{\"action\":\"3. กดปุ่ม แสดงข้อมูล\",\"expected\":\"แสดงข้อมูลตามกองทุนที่เลือก และแสดงข้อมูลได้ถูกต้องตามกองทุนที่เลือก\"}]', 'สามารถกรองข้อมูลตามกองทุนได้ถูกต้องที่เลือก และแสดงข้อมูลได้ถูกต้อง', 'pass', 'พิจิตรา ไตรสุธา', '2026-03-18', NULL, '2026-03-18 10:18:02');
INSERT INTO `test_cases` VALUES (14, 'tc_1773804340173', 'TC-007', '1773547868171', 0, 'สามารถเพิ่ม ลบ แก้ไข ข้อมูลประเภทการชำระเงินได้', NULL, '[{\"action\":\"คลิกเมนู ทะเบียนประเภทการชำระเงิน\",\"expected\":\"แสดงข้อมูลประเภทการชำระเงิน มีปุ่มเพิ่มข้อมูล มีปุ่มลบ และ แก้ไขข้อมูลได้\"},{\"action\":\"คลิกปุ่ม เพิ่ม \",\"expected\":\"สามารถคีย์เพิ่มประเภทการชำระเงินได้\"},{\"action\":\"คลิกปุ่ม บันทึก\",\"expected\":\"สามารถบันทึกข้อมูลประเภทการชำระเงินที่เพิ่มได้\"},{\"action\":\"คลิกปุ่ม แก้ไข \",\"expected\":\"สามรถแก้ไขชื่อประเภทชำระเงินได้และบันทึกได้\"},{\"action\":\"คลิกปุ่ม ลบ\",\"expected\":\"สามารถลบข้อมูลประเภทการชำระเงินได้\"}]', 'สามารถเพิ่ม ลบ แก้ไข ข้อมูลประเภทการชำระเงินได้', 'pass', 'น้องเจี๊ยบ', '2026-03-18', NULL, '2026-03-18 10:25:19');
INSERT INTO `test_cases` VALUES (15, 'tc_1773804833225', 'TC-009', '1773665080710', 3, 'เลือกรายการใบแจ้งหนี้ เพื่อนำเข้า', 'สามารถเลือกรายการได้ ทั้งเลือกได้ทั้งหมด และเลือกเฉพาะรายการ', '[{\"action\":\"1. กดเลือกทั้งหมด\",\"expected\":\"เมื่อกดแล้วจะต้องเลือกรายการทั้งหมดที่มีการกรอง\"},{\"action\":\"2. กดไม่เลือกทั้งหมด\",\"expected\":\"เมื่อกดแล้ว จะต้องไม่เลือกรายการทั้งหมดที่มีการกรอง\"},{\"action\":\"3. กดนำเข้าใบแจ้งหนี้\",\"expected\":\"สามารถกดนำเข้าได้ จากที่มีการเลือก\"}]', 'กดเลือกทั้งหมดแล้วสามารถเลือกทุกรายการได้\nกดไม่เลือกทั้งหมด แล้วรายการไม่มีการเลือก\nกดนำเข้าข้อมูลได้', 'pass', 'พิจิตรา ไตรสุธา', '2026-03-18', NULL, '2026-03-18 10:33:49');
INSERT INTO `test_cases` VALUES (16, 'tc_1773806082883', 'TC-010', '1773665137027', 0, 'สามารถกรองตามกลุ่มลูกหนี้ที่มีการตั้งหนี้ไว้แล้ว', 'กรองข้อมูลตามกลุ่มลูกหนี้ได้', '[{\"action\":\"1. กดทะเบียนรายการตั้งลูกหนี้\",\"expected\":\"สามารถเปิดหน้าทะเบียนการตั้งลูกหนี้ได้\"},{\"action\":\"2. กดกลุ่มลูกหนี้\",\"expected\":\"สามารถกรองข้อมูลกลุ่มลูกหนี้\"},{\"action\":\"3. กดปุ่มแสดงข้อมูล\",\"expected\":\"สามารถกรองข้อมูลได้ถูกต้อง\"}]', 'สามารถกรองข้อมูลได้ถูกต้องตามข้อมูลกงอทุนที่เลือก', 'pass', 'พิจิตรา ไตรสุธา', '2026-03-18', NULL, '2026-03-18 10:54:39');
